import React from "react";

export default function SuccessScreen({ firstName, userId }) {
  return (
    <div className="scale-in" style={{
      display: "flex", flexDirection: "column", alignItems: "center",
      justifyContent: "center", padding: "40px 16px", textAlign: "center",
    }}>
      <div style={{ fontSize: "56px", marginBottom: "16px" }}>🎉</div>
      <h2 style={{ fontSize: "20px", fontWeight: 700, color: "var(--text-primary)", marginBottom: "8px" }}>
        Welcome, {firstName}!
      </h2>
      <p style={{ fontSize: "14px", color: "var(--text-muted)", lineHeight: 1.6, maxWidth: "300px" }}>
        Your ShopKart account has been created successfully. Start exploring millions of products and exclusive deals!
      </p>
      {userId && (
        <div style={{
          marginTop: "12px", fontSize: "11px", color: "var(--text-muted)",
          background: "#f5f5f5", borderRadius: "var(--radius-sm)",
          padding: "6px 14px", wordBreak: "break-all",
        }}>
          User ID: {userId}
        </div>
      )}
      <button
        style={{
          marginTop: "24px", padding: "13px 32px", background: "var(--accent)",
          border: "none", borderRadius: "var(--radius-sm)", color: "#fff",
          fontSize: "15px", fontWeight: 700, cursor: "pointer",
          boxShadow: "var(--shadow-btn)", width: "100%", maxWidth: "260px",
          minHeight: "48px",
        }}
        onMouseEnter={(e) => { e.target.style.background = "var(--accent-dark)"; }}
        onMouseLeave={(e) => { e.target.style.background = "var(--accent)"; }}
        onClick={() => alert("Redirecting to homepage… (add your router here)")}
      >
        Start Shopping 🛍
      </button>
    </div>
  );
}
